{
  "name": "MonoCalendar AI",
  "description": "A minimalist, aesthetic content calendar that uses AI to plan your strategy and script your videos based on your unique persona."
}

export interface UserProfile {
  name: string;
  postingDays: number[]; // 0 = Sunday, 1 = Monday, etc.
  persona: string; // Detailed description
  isOnboarded: boolean;
}

export interface DayPlan {
  date: string; // ISO Date string YYYY-MM-DD
  theme: string;
  description: string;
  isPosted?: boolean;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isLoading?: boolean;
}

export interface WeeklyPlanResponse {
  plans: {
    dayOffset: number; // 0 for today/start date, 1 for tomorrow...
    theme: string;
    description: string;
  }[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, WeeklyPlanResponse } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to get the model name
const MODEL_NAME = 'gemini-3-flash-preview';

export const generateWeeklyPlan = async (profile: UserProfile, startDate: Date): Promise<WeeklyPlanResponse> => {
  const daysOfWeek = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
  const activeDays = profile.postingDays.map(d => daysOfWeek[d]).join(", ");

  const prompt = `
    You are an expert content strategist. 
    User Persona: ${profile.persona}

    The user wants to post on these days: ${activeDays}.

    Generate a 7-day content plan starting from ${startDate.toDateString()}.
    For days that are NOT in the "active days" list, you can either suggest a rest day or a low-effort engagement post, but prioritize the user's schedule.

    The plan must be cohesive. Each day's theme should work with the others (e.g., build-up, climax, recap).

    Return a JSON object containing an array of plans.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            plans: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  dayOffset: { type: Type.INTEGER, description: "0 for the start date, 1 for the next day, etc." },
                  theme: { type: Type.STRING, description: "Short, punchy title for the content." },
                  description: { type: Type.STRING, description: "A 1-sentence summary of the idea." }
                },
                required: ["dayOffset", "theme", "description"]
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text) as WeeklyPlanResponse;
  } catch (error) {
    console.error("Error generating plan:", error);
    throw error;
  }
};

export const createChatSession = (profile: UserProfile, dayTheme: string, dayDescription: string) => {
  return ai.chats.create({
    model: MODEL_NAME,
    config: {
      systemInstruction: `
        You are a specialized content assistant for a creator.

        CREATOR PROFILE:
        ${profile.persona}

        CURRENT TASK:
        Planning content for a specific day.
        Theme: ${dayTheme}
        Context: ${dayDescription}

        Your goal is to help them execute this specific piece of content. 
        Be concise, creative, and aligned with their specific style.
        If asked for scripts, provide formatting (hooks, body, CTA).
      `
    }
  });
};

import React from 'react';

