import React, { useState } from 'react';
import { UserProfile } from '../types';
import { Button, Input, TextArea, CheckboxCard } from './UI';
import { ArrowRight, Sparkles } from 'lucide-react';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [persona, setPersona] = useState('');
  const [selectedDays, setSelectedDays] = useState<number[]>([]);

  const toggleDay = (index: number) => {
    setSelectedDays(prev => 
      prev.includes(index) ? prev.filter(d => d !== index) : [...prev, index]
    );
  };

  const handleNext = () => {
    if (step === 1 && name.trim()) setStep(2);
    else if (step === 2 && selectedDays.length > 0) setStep(3);
    else if (step === 3 && persona.trim()) {
      onComplete({
        name,
        postingDays: selectedDays.sort(),
        persona,
        isOnboarded: true
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 max-w-2xl mx-auto animate-fade-in">

      {/* Progress Indicator */}
      <div className="flex gap-2 mb-12">
        {[1, 2, 3].map(i => (
          <div key={i} className={`h-1 w-12 rounded-full transition-colors duration-300 ${i <= step ? 'bg-black' : 'bg-zinc-200'}`} />
        ))}
      </div>

      <div className="w-full space-y-8">
        {step === 1 && (
          <div className="space-y-6">
            <h1 className="text-4xl font-light tracking-tight text-black">
              Welcome. <br/> Let's build your <span className="font-serif italic font-medium">brand</span>.
            </h1>
            <p className="text-zinc-500 text-lg">First, what should we call you?</p>
            <Input 
              placeholder="Your Name or Brand Name" 
              value={name} 
              onChange={e => setName(e.target.value)}
              autoFocus
            />
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h1 className="text-3xl font-light text-black">Commitment.</h1>
            <p className="text-zinc-500 text-lg">Which days will you dedicate to posting?</p>
            <div className="grid grid-cols-4 gap-3 sm:grid-cols-7">
              {DAYS.map((day, i) => (
                <CheckboxCard 
                  key={day} 
                  label={day} 
                  checked={selectedDays.includes(i)} 
                  onChange={() => toggleDay(i)} 
                />
              ))}
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6">
            <h1 className="text-3xl font-light text-black">Identity.</h1>
            <p className="text-zinc-500 text-lg">Describe your style, niche, and voice in detail.</p>
            <p className="text-xs text-zinc-400 uppercase tracking-wider">Example</p>
            <div className="p-4 bg-zinc-50 border border-zinc-100 text-zinc-400 text-sm italic mb-2">
              "I am a minimal tech reviewer. My style is calm, objective, and high-quality. I focus on productivity tools and desk setups. I want to sound professional but accessible."
            </div>
            <TextArea 
              rows={6}
              placeholder="I create content about..." 
              value={persona} 
              onChange={e => setPersona(e.target.value)}
              autoFocus
            />
          </div>
        )}

        <div className="pt-8 flex justify-end">
          <Button onClick={handleNext} disabled={
            (step === 1 && !name) || 
            (step === 2 && selectedDays.length === 0) || 
            (step === 3 && !persona)
          }>
            {step === 3 ? (
              <>
                <Sparkles className="w-4 h-4" /> Generate Strategy
              </>
            ) : (
              <>
                Next <ArrowRight className="w-4 h-4" />
              </>
            )}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, DayPlan, ChatMessage } from '../types';
import { createChatSession } from '../services/geminiService';
import { Button } from './UI';
import { Send, Sparkles, FileText, Type } from 'lucide-react';
import { Chat, GenerateContentResponse } from "@google/genai";
import ReactMarkdown from 'react-markdown';

interface ChatInterfaceProps {
  dayPlan: DayPlan;
  userProfile: UserProfile;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ dayPlan, userProfile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize chat session
    chatSessionRef.current = createChatSession(userProfile, dayPlan.theme, dayPlan.description);

    // Initial greeting from AI
    const initialGreeting = async () => {
      setIsLoading(true);
      try {
        const result: GenerateContentResponse = await chatSessionRef.current!.sendMessage({
          message: "Introduce yourself briefly and ask how you can help with today's content theme." 
        });
        setMessages([{
          id: 'init',
          role: 'model',
          text: result.text || "Ready to plan. What do you need?"
        }]);
      } catch (err) {
        console.error(err);
      } finally {
        setIsLoading(false);
      }
    };
    initialGreeting();
  }, [dayPlan, userProfile]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (text: string) => {
    if (!text.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const result: GenerateContentResponse = await chatSessionRef.current.sendMessage({ message: text });
      const aiMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: result.text || "I couldn't generate a response."
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: "Error connecting to AI. Please try again." 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage(input);
    }
  };

  const presets = [
    { label: "Give me 3 concepts", icon: Sparkles, prompt: "Give me 3 distinct concepts for this video theme. Keep them concise." },
    { label: "Write a Script", icon: FileText, prompt: "Write a full script for a 60-second vertical video based on the best concept. Include a hook." },
    { label: "Refine Hook", icon: Type, prompt: "Give me 5 viral hooks for this specific idea." },
  ];

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Preset Actions */}
      <div className="flex gap-2 p-4 border-b border-zinc-100 overflow-x-auto no-scrollbar">
        {presets.map((p, i) => (
          <button 
            key={i}
            onClick={() => sendMessage(p.prompt)}
            disabled={isLoading}
            className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium uppercase tracking-wide border border-zinc-200 hover:bg-black hover:text-white hover:border-black transition-colors whitespace-nowrap rounded-sm"
          >
            <p.icon size={12} />
            {p.label}
          </button>
        ))}
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`
              max-w-[85%] rounded-lg p-4 text-sm leading-relaxed
              ${msg.role === 'user' 
                ? 'bg-zinc-100 text-black' 
                : 'bg-white border border-zinc-100 text-zinc-800'}
            `}>
              <ReactMarkdown>{msg.text}</ReactMarkdown>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="bg-white border border-zinc-100 p-4 rounded-lg flex items-center gap-2">
                <div className="w-2 h-2 bg-zinc-300 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                <div className="w-2 h-2 bg-zinc-300 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                <div className="w-2 h-2 bg-zinc-300 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 border-t border-zinc-100">
        <div className="relative flex items-center">
          <textarea 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your instructions..."
            rows={1}
            className="w-full pr-12 py-3 pl-4 bg-zinc-50 border border-transparent focus:bg-white focus:border-zinc-300 transition-all outline-none resize-none rounded-md"
            style={{ minHeight: '48px' }}
          />
          <button 
            onClick={() => sendMessage(input)}
            disabled={!input.trim() || isLoading}
            className="absolute right-2 p-2 text-zinc-400 hover:text-black disabled:opacity-30 transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

