import React, { useState } from 'react';
import { UserProfile } from '../types';
import { Button, Input, TextArea, CheckboxCard } from './UI';
import { ArrowRight, Sparkles, User, Building2, Youtube, Instagram } from 'lucide-react';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [brandType, setBrandType] = useState<'Personal' | 'Company' | null>(null);
  const [platform, setPlatform] = useState<'YouTube' | 'Instagram' | null>(null);
  const [name, setName] = useState('');
  const [persona, setPersona] = useState('');
  const [selectedDays, setSelectedDays] = useState<number[]>([]);

  const toggleDay = (index: number) => {
    setSelectedDays(prev => 
      prev.includes(index) ? prev.filter(d => d !== index) : [...prev, index]
    );
  };

  const handleNext = () => {
    if (step === 1 && brandType) setStep(2);
    else if (step === 2 && platform) setStep(3);
    else if (step === 3 && name.trim()) setStep(4);
    else if (step === 4 && selectedDays.length > 0) setStep(5);
    else if (step === 5 && persona.trim()) {
      onComplete({
        name,
        brandType: brandType!,
        platform: platform!,
        postingDays: selectedDays.sort(),
        persona,
        isOnboarded: true
      });
    }
  };

  const SelectionCard: React.FC<{
    icon: React.ElementType;
    label: string;
    selected: boolean;
    onClick: () => void;
  }> = ({ icon: Icon, label, selected, onClick }) => (
    <div 
      onClick={onClick}
      className={`
        cursor-pointer p-6 border rounded-xl transition-all duration-200 flex flex-col items-center justify-center gap-4 w-full h-40
        ${selected ? 'bg-black text-white border-black ring-2 ring-black ring-offset-2' : 'bg-white text-zinc-500 border-zinc-200 hover:border-black hover:text-black'}
      `}
    >
      <Icon size={32} strokeWidth={1.5} />
      <span className="font-medium text-lg tracking-wide">{label}</span>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 max-w-2xl mx-auto animate-fade-in">

      {/* Progress Indicator */}
      <div className="flex gap-2 mb-12">
        {[1, 2, 3, 4, 5].map(i => (
          <div key={i} className={`h-1 w-8 rounded-full transition-colors duration-300 ${i <= step ? 'bg-black' : 'bg-zinc-200'}`} />
        ))}
      </div>

      <div className="w-full space-y-8">

        {step === 1 && (
          <div className="space-y-8 animate-fade-in">
            <h1 className="text-4xl font-light tracking-tight text-black">
              First things first. <br/> What are you <span className="font-serif italic font-medium">building</span>?
            </h1>
            <div className="grid grid-cols-2 gap-4">
              <SelectionCard 
                icon={User} 
                label="Personal Brand" 
                selected={brandType === 'Personal'} 
                onClick={() => setBrandType('Personal')} 
              />
              <SelectionCard 
                icon={Building2} 
                label="Company" 
                selected={brandType === 'Company'} 
                onClick={() => setBrandType('Company')} 
              />
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-8 animate-fade-in">
            <h1 className="text-4xl font-light tracking-tight text-black">
              Choose your stage.
            </h1>
            <div className="grid grid-cols-2 gap-4">
              <SelectionCard 
                icon={Youtube} 
                label="YouTube" 
                selected={platform === 'YouTube'} 
                onClick={() => setPlatform('YouTube')} 
              />
              <SelectionCard 
                icon={Instagram} 
                label="Instagram" 
                selected={platform === 'Instagram'} 
                onClick={() => setPlatform('Instagram')} 
              />
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-fade-in">
            <h1 className="text-4xl font-light tracking-tight text-black">
              Identity. <br/> What should we call {brandType === 'Company' ? 'it' : 'you'}?
            </h1>
            <p className="text-zinc-500 text-lg">
              {brandType === 'Company' ? 'Company or Brand Name' : 'Your Name or Handle'}
            </p>
            <Input 
              placeholder="Enter name..." 
              value={name} 
              onChange={e => setName(e.target.value)}
              autoFocus
            />
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-fade-in">
            <h1 className="text-3xl font-light text-black">Consistency.</h1>
            <p className="text-zinc-500 text-lg">Which days will you dedicate to posting on {platform}?</p>
            <div className="grid grid-cols-4 gap-3 sm:grid-cols-7">
              {DAYS.map((day, i) => (
                <CheckboxCard 
                  key={day} 
                  label={day} 
                  checked={selectedDays.includes(i)} 
                  onChange={() => toggleDay(i)} 
                />
              ))}
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6 animate-fade-in">
            <h1 className="text-3xl font-light text-black">Style & Niche.</h1>
            <p className="text-zinc-500 text-lg">Describe the content style for your {platform} audience.</p>

            <div className="p-4 bg-zinc-50 border border-zinc-100 rounded-lg">
              <p className="text-xs text-zinc-400 uppercase tracking-wider mb-2">Example</p>
              <p className="text-zinc-500 text-sm italic">
                {platform === 'YouTube' 
                  ? '"Long-form educational content about coding. High energy, fast-paced editing, lots of screen shares. I want to be authoritative but fun."'
                  : '"Aesthetic lifestyle reels. Minimalist visual style, calm voiceovers, focus on daily routines and productivity. Warm filters, slow pacing."'
                }
              </p>
            </div>

            <TextArea 
              rows={6}
              placeholder={`Describe your ${brandType === 'Company' ? 'brand' : 'personal'} style...`} 
              value={persona} 
              onChange={e => setPersona(e.target.value)}
              autoFocus
            />
          </div>
        )}

        <div className="pt-8 flex justify-end">
          <Button onClick={handleNext} disabled={
            (step === 1 && !brandType) ||
            (step === 2 && !platform) ||
            (step === 3 && !name) || 
            (step === 4 && selectedDays.length === 0) || 
            (step === 5 && !persona)
          }>
            {step === 5 ? (
              <>
                <Sparkles className="w-4 h-4" /> Generate Strategy
              </>
            ) : (
              <>
                Next <ArrowRight className="w-4 h-4" />
              </>
            )}
          </Button>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, WeeklyPlanResponse } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to get the model name
const MODEL_NAME = 'gemini-3-flash-preview';

export const generateWeeklyPlan = async (profile: UserProfile, startDate: Date): Promise<WeeklyPlanResponse> => {
  const daysOfWeek = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
  const activeDays = profile.postingDays.map(d => daysOfWeek[d]).join(", ");

  const prompt = `
    You are an expert content strategist for a ${profile.brandType} brand on ${profile.platform}.
    User Persona/Style: ${profile.persona}

    The user wants to post on these days: ${activeDays}.

    Generate a 7-day content plan starting from ${startDate.toDateString()}.
    For days that are NOT in the "active days" list, you can either suggest a rest day or a low-effort engagement post (like a ${profile.platform === 'YouTube' ? 'Community Post' : 'Story'}), but prioritize the user's schedule.

    The plan must be cohesive and tailored for ${profile.platform}. 
    Each day's theme should work with the others (e.g., build-up, climax, recap).

    Return a JSON object containing an array of plans.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            plans: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  dayOffset: { type: Type.INTEGER, description: "0 for the start date, 1 for the next day, etc." },
                  theme: { type: Type.STRING, description: "Short, punchy title for the content." },
                  description: { type: Type.STRING, description: "A 1-sentence summary of the idea." }
                },
                required: ["dayOffset", "theme", "description"]
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text) as WeeklyPlanResponse;
  } catch (error) {
    console.error("Error generating plan:", error);
    throw error;
  }
};

export const createChatSession = (profile: UserProfile, dayTheme: string, dayDescription: string) => {
  return ai.chats.create({
    model: MODEL_NAME,
    config: {
      systemInstruction: `
        You are a specialized content assistant for a ${profile.brandType} brand on ${profile.platform}.

        BRAND/CREATOR PROFILE:
        ${profile.persona}

        CURRENT TASK:
        Planning content for a specific day.
        Theme: ${dayTheme}
        Context: ${dayDescription}

        Your goal is to help them execute this specific piece of content for ${profile.platform}.
        Be concise, creative, and aligned with their specific style.

        If asked for scripts, provide formatting appropriate for ${profile.platform} (e.g., ${profile.platform === 'YouTube' ? 'Hook, Intro, Value Props, CTA' : 'Visual Hook, Audio cue, Caption'}).
      `
    }
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, DayPlan, ChatMessage } from '../types';
import { createChatSession } from '../services/geminiService';
import { Button } from './UI';
import { Send, Sparkles, FileText, Type, Video, Image as ImageIcon } from 'lucide-react';
import { Chat, GenerateContentResponse } from "@google/genai";
import ReactMarkdown from 'react-markdown';

interface ChatInterfaceProps {
  dayPlan: DayPlan;
  userProfile: UserProfile;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ dayPlan, userProfile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize chat session
    chatSessionRef.current = createChatSession(userProfile, dayPlan.theme, dayPlan.description);

    // Initial greeting from AI
    const initialGreeting = async () => {
      setIsLoading(true);
      try {
        const result: GenerateContentResponse = await chatSessionRef.current!.sendMessage({
          message: "Introduce yourself briefly as my assistant for this platform and ask how you can help with today's content theme." 
        });
        setMessages([{
          id: 'init',
          role: 'model',
          text: result.text || "Ready to plan. What do you need?"
        }]);
      } catch (err) {
        console.error(err);
      } finally {
        setIsLoading(false);
      }
    };
    initialGreeting();
  }, [dayPlan, userProfile]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (text: string) => {
    if (!text.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const result: GenerateContentResponse = await chatSessionRef.current.sendMessage({ message: text });
      const aiMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: result.text || "I couldn't generate a response."
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: "Error connecting to AI. Please try again." 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage(input);
    }
  };

  // Dynamic presets based on platform
  const getPresets = () => {
    const base = [
      { label: "Brainstorm Ideas", icon: Sparkles, prompt: "Give me 3 distinct execution angles for this theme." },
    ];

    if (userProfile.platform === 'YouTube') {
      return [
        ...base,
        { label: "Outline Script", icon: FileText, prompt: "Write a detailed script outline with timestamps." },
        { label: "Thumbnail Ideas", icon: ImageIcon, prompt: "Describe 3 clickable thumbnail concepts with text overlays." },
        { label: "Title Options", icon: Type, prompt: "Give me 5 SEO-friendly viral titles." }
      ];
    } else { // Instagram
      return [
        ...base,
        { label: "Reel Script", icon: Video, prompt: "Write a 30-second Reel script with visual cues and audio suggestions." },
        { label: "Caption & Hashtags", icon: Type, prompt: "Write an engaging caption with a hook and relevant hashtags." },
        { label: "Story Sequence", icon: ImageIcon, prompt: "Plan a 3-slide Story sequence to promote this." }
      ];
    }
  };

  const presets = getPresets();

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Preset Actions */}
      <div className="flex gap-2 p-4 border-b border-zinc-100 overflow-x-auto no-scrollbar">
        {presets.map((p, i) => (
          <button 
            key={i}
            onClick={() => sendMessage(p.prompt)}
            disabled={isLoading}
            className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium uppercase tracking-wide border border-zinc-200 hover:bg-black hover:text-white hover:border-black transition-colors whitespace-nowrap rounded-sm"
          >
            <p.icon size={12} />
            {p.label}
          </button>
        ))}
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`
              max-w-[85%] rounded-lg p-4 text-sm leading-relaxed
              ${msg.role === 'user' 
                ? 'bg-zinc-100 text-black' 
                : 'bg-white border border-zinc-100 text-zinc-800'}
            `}>
              <ReactMarkdown>{msg.text}</ReactMarkdown>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="bg-white border border-zinc-100 p-4 rounded-lg flex items-center gap-2">
                <div className="w-2 h-2 bg-zinc-300 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                <div className="w-2 h-2 bg-zinc-300 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                <div className="w-2 h-2 bg-zinc-300 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 border-t border-zinc-100">
        <div className="relative flex items-center">
          <textarea 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={`Ask about your ${userProfile.platform} content...`}
            rows={1}
            className="w-full pr-12 py-3 pl-4 bg-zinc-50 border border-transparent focus:bg-white focus:border-zinc-300 transition-all outline-none resize-none rounded-md"
            style={{ minHeight: '48px' }}
          />
          <button 
            onClick={() => sendMessage(input)}
            disabled={!input.trim() || isLoading}
            className="absolute right-2 p-2 text-zinc-400 hover:text-black disabled:opacity-30 transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

