import React, { useState } from 'react';
import { UserProfile } from '../types';
import { Button, Input, TextArea, CheckboxCard } from './UI';
import { ArrowRight, Sparkles, User, Building2, Youtube, Instagram, Layers } from 'lucide-react';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [brandType, setBrandType] = useState<'Personal' | 'Company' | null>(null);
  const [platform, setPlatform] = useState<'YouTube' | 'Instagram' | null>(null);
  const [name, setName] = useState('');
  const [persona, setPersona] = useState('');
  const [pillarsInput, setPillarsInput] = useState('');
  const [selectedDays, setSelectedDays] = useState<number[]>([]);

  const toggleDay = (index: number) => {
    setSelectedDays(prev => 
      prev.includes(index) ? prev.filter(d => d !== index) : [...prev, index]
    );
  };

  const handleNext = () => {
    if (step === 1 && brandType) setStep(2);
    else if (step === 2 && platform) setStep(3);
    else if (step === 3 && name.trim()) setStep(4);
    else if (step === 4 && selectedDays.length > 0) setStep(5);
    else if (step === 5 && pillarsInput.trim()) setStep(6);
    else if (step === 6 && persona.trim()) {
      onComplete({
        name,
        brandType: brandType!,
        platform: platform!,
        postingDays: selectedDays.sort(),
        contentPillars: pillarsInput.split(',').map(p => p.trim()).filter(p => p),
        persona,
        isOnboarded: true
      });
    }
  };

  const SelectionCard: React.FC<{
    icon: React.ElementType;
    label: string;
    selected: boolean;
    onClick: () => void;
  }> = ({ icon: Icon, label, selected, onClick }) => (
    <div 
      onClick={onClick}
