  const [selectedDays, setSelectedDays] = useState<number[]>([]);

  const toggleDay = (index: number) => {
    setSelectedDays(prev => 
      prev.includes(index) ? prev.filter(d => d !== index) : [...prev, index]
    );
  };

  const addPillar = () => {
    if (currentPillar.trim() && !pillars.includes(currentPillar.trim())) {
      setPillars([...pillars, currentPillar.trim()]);
      setCurrentPillar('');
    }
  };

  const removePillar = (pillarToRemove: string) => {
    setPillars(pillars.filter(p => p !== pillarToRemove));
  };

  const handleNext = () => {
    if (step === 1 && brandType) setStep(2);
    else if (step === 2 && platform) setStep(3);
    else if (step === 3 && name.trim()) setStep(4);
    else if (step === 4 && selectedDays.length > 0) setStep(5);
    else if (step === 5 && pillars.length > 0) setStep(6);
    else if (step === 6 && persona.trim()) {
      onComplete({
        name,
        brandType: brandType!,
        platform: platform!,
        postingDays: selectedDays.sort(),
        contentPillars: pillars,
        persona,
        isOnboarded: true
      });
