            {activeTab === 'schedule' && (
              <div className="space-y-8 animate-fade-in">
                <div className="space-y-4">
                  <h3 className="text-lg font-medium text-black">Posting Schedule</h3>
                  <div className="grid grid-cols-7 gap-2">
                    {DAYS.map((day, i) => (
                      <CheckboxCard 
                        key={day} 
                        label={day} 
                        checked={profile.postingDays.includes(i)} 
